/// Hydrate in-memory scheduler state from on-chain Scheduler storage.
///
/// This is used as a strict startup gate to restore scheduled jobs after node restart.
pub fn hydrate_from_storage<DB: Database>(
    &self,
    db: &mut DB,
    current_block: u64,
) -> Result<HydrationStats, SchedulingError> {
    let scheduler_address = self.get_scheduler_address();
    let active_calls =
        ritual_scheduled_verification::read_active_scheduled_calls(db, Some(scheduler_address))
            .map_err(|e| {
                SchedulingError::StartupHydrationFailed(format!(
                    "failed to scan active scheduled calls: {}",
                    e
                ))
            })?;
